  'united states':[-4,'Estados Unidos'],'canada':[-4,'Canadá'],'canadá':[-4,'Canadá']
};
function detectarPais(texto) {
  const t = (texto||'').toLowerCase().replace(/[¡!.,;:]/g,' ').replace(/\s+/g,' ').trim();
  if (t.length > 45) return null;
  for (const [p, info] of Object.entries(PAISES)) {
    if (t === p || t === 'estoy en '+p || t === 'desde '+p || t === 'en '+p || t === 'soy de '+p || t === 'de '+p || (t.endsWith(' '+p) && t.split(' ').length <= 4)) {
      return { nombre: info[1], offset: info[0] };
    }
  }
  return null;
}
function flagEmoji(code) {
  if (!code) return '⚽';
  if (code === 'gb-sct') return '🏴󠁧󠁢󠁳󠁣󠁴󠁿';
  if (code === 'gb-eng') return '🏴󠁧󠁢󠁥󠁮󠁧󠁿';
  if (code === 'gb-wls') return '🏴󠁧󠁢󠁷󠁬󠁳󠁿';
  return String.fromCodePoint(...[...code.toUpperCase()].map(c => 127397 + c.charCodeAt(0)));
}
function mensajePais(pais) {
  const ahora = Date.now();
  const prox = CAL.map(p => ({...p, ts: Date.parse(p.u)}))
    .filter(p => p.ts > ahora - 2*3600000)
    .sort((x,y) => x.ts - y.ts)
    .slice(0, 3);
  const dias = ['dom','lun','mar','mié','jue','vie','sáb'];
  const lines = ['⏰ ¡Listo! Horarios en hora de ' + pais.nombre + ':', ''];
  for (const p of prox) {
    const d = new Date(p.ts + pais.offset*3600000);
    let h = d.getUTCHours(); const m = d.getUTCMinutes();
    const ampm = h >= 12 ? 'PM' : 'AM'; h = h % 12 || 12;
    lines.push(flagEmoji(p.hf) + ' ' + p.h + ' vs ' + p.a + ' ' + flagEmoji(p.af));
    lines.push('   ' + dias[d.getUTCDay()] + ' · ' + h + ':' + String(m).padStart(2,'0') + ' ' + ampm);
    lines.push('');
  }
  lines.push('✅ Guardé tu país — desde ahora todas tus alertas llegarán con tu hora local ⚽');
  lines.push('');
  lines.push('#RODAI Sport');
  return lines.join('\n');
}

const msg = $('WA — Extraer Mensaje').first().json;
const text = (msg.text || '').trim();
const phone = msg.phone;
const rows = $input.all();
const dbRow = (rows.length > 0 && rows[0].json && rows[0].json.estado) ? rows[0].json : {};
const estado = dbRow.estado || null;
const nombre_temp = dbRow.nombre_temp || null;

let accion = 'switch_normal';
let telefono_limpio = '';
const msg_type = msg.msg_type || 'text';

// Reacciones (👍 a una alerta) y mensajes de sistema: NO responder nada
if (['reaction', 'system', 'unsupported', 'ephemeral'].includes(msg_type)) {
  return [{ json: { accion: 'ignorar', msg_type, phone, text, name: msg.name || '', estado, nombre_temp, telefono_limpio } }];
}

// Mensajes que no son texto (sticker, audio, imagen, video...): respuesta dedicada
if (msg_type !== 'text' && !estado) {
  return [{ json: { accion: 'no_texto', msg_type, phone, text, name: msg.name || '', estado, nombre_temp, telefono_limpio } }];
}

if (estado === 'pregunta_activar') {
  if (text === '1') accion = 'pide_nombre';
  else if (text === '2') accion = 'cancelar';
  else accion = 'repregunta';
} else if (estado === 'esperando_nombre') {
  accion = 'pide_telefono';
} else if (estado === 'esperando_telefono') {
  telefono_limpio = text.replace(/[^0-9]/g, '');
  if (telefono_limpio.length >= 8 && telefono_limpio.length <= 15) accion = 'enviar_pago';
  else accion = 'telefono_invalido';
} else {
  // ONBOARDING_PAGO: false = ALTA va directo a bienvenida simple (demo).
  // Cambiar a true despues del partido de Corea del Sur para activar flujo de pago.
  const ONBOARDING_PAGO = false;
  if (/^\s*\d{1,2}\s*[-\u2013\u2014aA]\s*\d{1,2}\s*$/.test(text)) accion = 'prediccion';
  else if (ONBOARDING_PAGO && text.toLowerCase().includes('alta')) accion = 'onboard_start';
  else { const _p = detectarPais(text); if (_p) { return [{ json: { accion: 'pais', phone, text, name: msg.name || '', estado, nombre_temp, telefono_limpio, pais_msg: mensajePais(_p), pais_nombre: _p.nombre.replace(/'/g,''), pais_offset: _p.offset } }]; } }
}

return [{ json: { accion, phone, text, name: msg.name || '', estado, nombre_temp, telefono_limpio } }];

