const PAISES = {
  'el salvador':[-6,'El Salvador'],'salvador':[-6,'El Salvador'],'mexico':[-6,'México'],'méxico':[-6,'México'],
  'guatemala':[-6,'Guatemala'],'honduras':[-6,'Honduras'],'nicaragua':[-6,'Nicaragua'],'costa rica':[-6,'Costa Rica'],
